// Analyze overall system state and determine control actions
// This is the main control logic coordinator

// Get latest data from all devices
const pvData = global.get('pv_data') || {};
const gensetData = global.get('genset_data') || {};
const gridData = global.get('power_meter_data') || {};

// Get system configuration
const config = global.get('system_config') || {
    max_pv_power: 10000, // W
    max_genset_power: 15000, // W
    min_spinning_reserve: 2000, // W
    max_export_power: 5000, // W
    zero_export_enabled: false,
    load_sharing_enabled: true,
    fuel_saving_enabled: true,
    grid_connected: true
};

// Calculate system parameters
const pvPower = pvData.ac_power || 0;
const gensetPower = gensetData.ac_power || 0;
const gridPower = gridData.total_active_power || 0; // Positive = import, Negative = export
const totalGeneration = pvPower + gensetPower;
const loadPower = totalGeneration + gridPower; // Total load

// Determine system state
const systemState = {
    timestamp: new Date().toISOString(),
    pv_power: pvPower,
    genset_power: gensetPower,
    grid_power: gridPower,
    load_power: loadPower,
    total_generation: totalGeneration,
    grid_connected: gridData.grid_connected || false,
    genset_running: gensetData.running || false,
    pv_available: pvPower > 100,
    excess_power: totalGeneration - loadPower,
    deficit_power: loadPower - totalGeneration
};

// Store system state for other flows
global.set('system_state', systemState);

// Generate control decisions
const controlDecisions = {
    timestamp: systemState.timestamp,
    pv_curtailment: 0, // Amount to curtail PV (W)
    genset_target_power: 0, // Target genset power (W)
    genset_start_stop: 'maintain', // 'start', 'stop', 'maintain'
    export_limit_active: false,
    load_sharing_active: false,
    spinning_reserve_required: config.min_spinning_reserve
};

// Control Logic Implementation
if (config.grid_connected && systemState.grid_connected) {
    // Grid-connected mode
    if (config.zero_export_enabled) {
        // Zero export control
        if (systemState.excess_power > 100) {
            // Too much generation, curtail PV or reduce genset
            if (systemState.genset_running && gensetPower > 1000) {
                // Reduce genset first for fuel saving
                const reduction = Math.min(systemState.excess_power, gensetPower - 500);
                controlDecisions.genset_target_power = gensetPower - reduction;
            } else if (pvPower > 1000) {
                // Curtail PV if needed
                controlDecisions.pv_curtailment = Math.min(systemState.excess_power, pvPower * 0.1);
            }
        }
    } else {
        // Limited export mode
        const exportPower = Math.abs(Math.min(0, gridPower));
        if (exportPower > config.max_export_power) {
            const excessExport = exportPower - config.max_export_power;
            if (systemState.genset_running && gensetPower > 1000) {
                const reduction = Math.min(excessExport, gensetPower - 500);
                controlDecisions.genset_target_power = gensetPower - reduction;
            } else {
                controlDecisions.pv_curtailment = Math.min(excessExport, pvPower * 0.1);
            }
            controlDecisions.export_limit_active = true;
        }
    }

    // Genset control for grid-connected mode
    if (config.fuel_saving_enabled && pvPower > 2000) {
        // Sufficient solar, can reduce or stop genset
        if (systemState.genset_running) {
            const availableCapacity = pvPower + config.max_export_power;
            if (availableCapacity > loadPower + config.min_spinning_reserve) {
                if (gensetPower > 1000) {
                    controlDecisions.genset_target_power = Math.max(500, gensetPower - 1000);
                } else {
                    controlDecisions.genset_start_stop = 'stop';
                }
            }
        }
    } else if (systemState.deficit_power > config.min_spinning_reserve) {
        // Need more generation
        if (!systemState.genset_running) {
            controlDecisions.genset_start_stop = 'start';
            controlDecisions.genset_target_power = Math.min(config.max_genset_power, 
                                                          systemState.deficit_power + config.min_spinning_reserve);
        } else {
            controlDecisions.genset_target_power = Math.min(config.max_genset_power, 
                                                          gensetPower + systemState.deficit_power);
        }
    }
} else {
    // Off-grid mode
    const totalCapacity = pvPower + (systemState.genset_running ? config.max_genset_power : 0);

    if (loadPower > totalCapacity * 0.8) {
        // High load, need genset
        if (!systemState.genset_running) {
            controlDecisions.genset_start_stop = 'start';
            controlDecisions.genset_target_power = Math.min(config.max_genset_power, 
                                                          loadPower - pvPower + config.min_spinning_reserve);
        } else {
            // Adjust genset power for load sharing
            const targetGensetPower = loadPower - pvPower + config.min_spinning_reserve;
            controlDecisions.genset_target_power = Math.min(config.max_genset_power, 
                                                          Math.max(1000, targetGensetPower));
            controlDecisions.load_sharing_active = true;
        }
    } else if (pvPower > loadPower + config.min_spinning_reserve && systemState.genset_running) {
        // Excess solar, can reduce genset
        const excessSolar = pvPower - loadPower;
        if (excessSolar > config.min_spinning_reserve) {
            if (gensetPower > 1000) {
                controlDecisions.genset_target_power = Math.max(500, gensetPower - Math.min(1000, excessSolar));
            } else {
                controlDecisions.genset_start_stop = 'stop';
            }
        }
    } else if (systemState.deficit_power > 500) {
        // Need more generation
        if (!systemState.genset_running) {
            controlDecisions.genset_start_stop = 'start';
            controlDecisions.genset_target_power = Math.min(config.max_genset_power, 
                                                          systemState.deficit_power + config.min_spinning_reserve);
        }
    }
}

// Store control decisions
global.set('control_decisions', controlDecisions);

// Output messages for different control actions
const messages = [];

// PV Control Message
if (controlDecisions.pv_curtailment > 0) {
    messages.push({
        topic: 'pv/control',
        payload: {
            action: 'curtail',
            amount: controlDecisions.pv_curtailment,
            percentage: (controlDecisions.pv_curtailment / pvPower) * 100
        }
    });
}

// Genset Control Message
if (controlDecisions.genset_start_stop !== 'maintain' || controlDecisions.genset_target_power !== gensetPower) {
    messages.push({
        topic: 'genset/control',
        payload: {
            action: controlDecisions.genset_start_stop,
            target_power: controlDecisions.genset_target_power,
            current_power: gensetPower
        }
    });
}

// System Status Message
messages.push({
    topic: 'system/status',
    payload: {
        state: systemState,
        decisions: controlDecisions,
        mode: config.grid_connected && systemState.grid_connected ? 'grid-connected' : 'off-grid'
    }
});

node.log(`Control Decision: PV=${pvPower}W, Genset=${gensetPower}W, Load=${loadPower}W, Grid=${gridPower}W`);

return [messages];

// Control PV inverter output for curtailment or optimization
const control = msg.payload;

if (control.action === 'curtail') {
    // Calculate new power limit as percentage
    const currentPower = global.get('pv_data')?.ac_power || 0;
    const newLimit = Math.max(0, currentPower - control.amount);
    const limitPercentage = currentPower > 0 ? (newLimit / currentPower) * 100 : 100;

    // Modbus write command to set power limit
    const modbusWrite = {
        topic: 'pv_inverter_control',
        payload: {
            'fc': 6, // Function code 6 (Write Single Register)
            'unitid': 1,
            'address': 40100, // Power limit register (example)
            'quantity': 1,
            'values': [Math.round(limitPercentage * 10)] // Percentage * 10 for 0.1% resolution
        }
    };

    node.log(`PV Curtailment: ${control.amount}W (${control.percentage.toFixed(1)}%)`);

    // Log the control action
    const logEntry = {
        timestamp: new Date().toISOString(),
        device: 'pv_inverter',
        action: 'curtailment',
        amount: control.amount,
        percentage: control.percentage
    };

    return [modbusWrite, {topic: 'control/log', payload: logEntry}];
} else {
    // Remove curtailment - set to 100%
    const modbusWrite = {
        topic: 'pv_inverter_control',
        payload: {
            'fc': 6,
            'unitid': 1,
            'address': 40100,
            'quantity': 1,
            'values': [1000] // 100.0%
        }
    };

    return [modbusWrite, null];
}

// Control genset start/stop and power output
const control = msg.payload;
const currentGensetData = global.get('genset_data') || {};

const messages = [];

if (control.action === 'start' && !currentGensetData.running) {
    // Start genset
    const startCommand = {
        topic: 'genset_control',
        payload: {
            'fc': 6, // Write Single Register
            'unitid': 1,
            'address': 40200, // Start/Stop register (example)
            'quantity': 1,
            'values': [1] // 1 = Start
        }
    };

    messages.push(startCommand);

    // Set initial power target after start delay
    setTimeout(() => {
        const powerCommand = {
            topic: 'genset_control',
            payload: {
                'fc': 6,
                'unitid': 1,
                'address': 40201, // Power setpoint register
                'quantity': 1,
                'values': [Math.round(control.target_power / 10)] // Power in 10W increments
            }
        };
        messages.push(powerCommand);
    }, 30000); // 30 second delay for genset startup

    node.log(`Genset Start Command - Target Power: ${control.target_power}W`);

} else if (control.action === 'stop' && currentGensetData.running) {
    // Stop genset
    const stopCommand = {
        topic: 'genset_control',
        payload: {
            'fc': 6,
            'unitid': 1,
            'address': 40200,
            'quantity': 1,
            'values': [0] // 0 = Stop
        }
    };

    messages.push(stopCommand);
    node.log('Genset Stop Command');

} else if (control.action === 'maintain' && currentGensetData.running) {
    // Adjust power output
    const currentPower = currentGensetData.ac_power || 0;
    const powerDifference = Math.abs(control.target_power - currentPower);

    // Only adjust if difference is significant (>5% or >500W)
    if (powerDifference > Math.max(currentPower * 0.05, 500)) {
        const powerCommand = {
            topic: 'genset_control',
            payload: {
                'fc': 6,
                'unitid': 1,
                'address': 40201,
                'quantity': 1,
                'values': [Math.round(control.target_power / 10)]
            }
        };

        messages.push(powerCommand);
        node.log(`Genset Power Adjustment: ${currentPower}W -> ${control.target_power}W`);
    }
}

// Log the control action
const logEntry = {
    timestamp: new Date().toISOString(),
    device: 'genset',
    action: control.action,
    target_power: control.target_power,
    current_power: control.current_power
};

messages.push({topic: 'control/log', payload: logEntry});

return [messages];

// Log system status and control decisions
const status = msg.payload;

// Create comprehensive log entry
const logEntry = {
    timestamp: status.state.timestamp,
    mode: status.mode,
    system_state: status.state,
    control_decisions: status.decisions,
    fuel_savings: {
        pv_utilization: status.state.pv_power > 0 ? (status.state.pv_power / (status.state.pv_power + status.state.genset_power)) * 100 : 0,
        genset_load_factor: status.state.genset_power > 0 ? (status.state.genset_power / 15000) * 100 : 0, // Assuming 15kW genset
        estimated_fuel_rate: status.state.genset_power > 0 ? (status.state.genset_power * 0.3 / 1000) : 0 // L/hr estimation
    },
    efficiency: {
        system_efficiency: status.state.total_generation > 0 ? (status.state.load_power / status.state.total_generation) * 100 : 0,
        grid_interaction: status.state.grid_power
    }
};

// Store for reporting
const historicalData = context.get('system_history') || [];
historicalData.push(logEntry);

// Keep only last 1000 entries in memory
if (historicalData.length > 1000) {
    historicalData.shift();
}
context.set('system_history', historicalData);

// Calculate daily statistics
const today = new Date().toDateString();
const todayData = historicalData.filter(entry => new Date(entry.timestamp).toDateString() === today);

if (todayData.length > 0) {
    const dailyStats = {
        date: today,
        avg_pv_power: todayData.reduce((sum, entry) => sum + entry.system_state.pv_power, 0) / todayData.length,
        avg_genset_power: todayData.reduce((sum, entry) => sum + entry.system_state.genset_power, 0) / todayData.length,
        avg_load_power: todayData.reduce((sum, entry) => sum + entry.system_state.load_power, 0) / todayData.length,
        total_pv_energy: todayData.reduce((sum, entry) => sum + (entry.system_state.pv_power * 10 / 3600), 0) / 1000, // kWh
        total_genset_energy: todayData.reduce((sum, entry) => sum + (entry.system_state.genset_power * 10 / 3600), 0) / 1000, // kWh
        estimated_fuel_consumed: todayData.reduce((sum, entry) => sum + (entry.fuel_savings.estimated_fuel_rate * 10 / 3600), 0), // Liters
        pv_contribution: 0
    };

    dailyStats.pv_contribution = dailyStats.total_pv_energy / (dailyStats.total_pv_energy + dailyStats.total_genset_energy) * 100;

    context.set('daily_stats', dailyStats);
}

// Send to dashboard and database
return [{
    topic: 'system/log',
    payload: logEntry
}, {
    topic: 'dashboard/system',
    payload: {
        state: status.state,
        decisions: status.decisions,
        mode: status.mode
    }
}];

// Log successful control commands
const timestamp = new Date().toISOString();
node.log(`Control command executed successfully at ${timestamp}`);

msg.payload = {
    timestamp: timestamp,
    status: 'success',
    command: msg.topic,
    response: msg.payload
};

return msg;

// Handle control command errors
const timestamp = new Date().toISOString();
node.error(`Control command failed at ${timestamp}: ${msg.payload}`);

// Create alert for control failure
const alert = {
    type: 'warning',
    device: 'control_system',
    message: `Control command failed: ${msg.topic}`,
    timestamp: timestamp,
    error_details: msg.payload
};

msg.payload = alert;
msg.topic = 'alert/warning';

return msg;

// Log all control actions to database and file
const logData = msg.payload;

// Format for database storage
const dbEntry = {
    timestamp: logData.timestamp || new Date().toISOString(),
    action_type: 'control',
    device: logData.device || 'system',
    action: logData.action || 'unknown',
    parameters: JSON.stringify(logData)
};

// Format for file logging
const csvLine = `${dbEntry.timestamp},${dbEntry.device},${dbEntry.action},${dbEntry.parameters}\n`;

return [{
    topic: 'db/control_log',
    payload: dbEntry
}, {
    topic: 'file/control_log',
    payload: csvLine
}];

// Process manual control commands from dashboard
const controls = msg.payload;

// Set manual override flag
if (controls.manual_override) {
    global.set('manual_override', true);
    node.log('Manual override activated');
} else {
    global.set('manual_override', false);
    node.log('Manual override deactivated');
}

const messages = [];

// PV Control
if (controls.pv_limit !== undefined && controls.pv_limit !== 100) {
    const pvData = global.get('pv_data') || {};
    const currentPower = pvData.ac_power || 0;
    const targetPower = currentPower * (controls.pv_limit / 100);
    const curtailment = currentPower - targetPower;

    messages.push({
        topic: 'pv/control',
        payload: {
            action: 'curtail',
            amount: curtailment,
            percentage: 100 - controls.pv_limit
        }
    });
}

// Genset Control
if (controls.genset_command && controls.genset_command !== 'maintain') {
    messages.push({
        topic: 'genset/control',
        payload: {
            action: controls.genset_command,
            target_power: controls.genset_power || 0,
            current_power: global.get('genset_data')?.ac_power || 0
        }
    });
} else if (controls.genset_power && controls.genset_power > 0) {
    messages.push({
        topic: 'genset/control',
        payload: {
            action: 'maintain',
            target_power: controls.genset_power,
            current_power: global.get('genset_data')?.ac_power || 0
        }
    });
}

// Log manual control action
const logEntry = {
    timestamp: new Date().toISOString(),
    device: 'manual_control',
    action: 'manual_command',
    parameters: controls
};

messages.push({
    topic: 'control/log',
    payload: logEntry
});

node.log(`Manual control executed: ${JSON.stringify(controls)}`);

return [messages];

// Update system configuration
const newConfig = msg.payload;

// Store new configuration
global.set('system_config', newConfig);

// Log configuration change
const logEntry = {
    timestamp: new Date().toISOString(),
    device: 'system',
    action: 'config_update',
    parameters: newConfig
};

node.log(`System configuration updated: ${JSON.stringify(newConfig)}`);

// Send confirmation
msg.payload = {
    status: 'success',
    message: 'Configuration updated successfully',
    timestamp: new Date().toISOString(),
    config: newConfig
};

return [msg, {topic: 'control/log', payload: logEntry}];

// Process emergency stop command
node.warn('EMERGENCY STOP ACTIVATED!');

// Set emergency flag
global.set('emergency_stop', true);
global.set('manual_override', true);

const messages = [];

// Stop genset immediately
messages.push({
    topic: 'genset/control',
    payload: {
        action: 'stop',
        target_power: 0,
        current_power: global.get('genset_data')?.ac_power || 0
    }
});

// Curtail PV to minimum
messages.push({
    topic: 'pv/control',
    payload: {
        action: 'curtail',
        amount: global.get('pv_data')?.ac_power || 0,
        percentage: 100
    }
});

// Create critical alert
messages.push({
    topic: 'alert/critical',
    payload: {
        type: 'critical',
        device: 'system',
        message: 'EMERGENCY STOP ACTIVATED - All generation stopped',
        timestamp: new Date().toISOString()
    }
});

// Log emergency action
messages.push({
    topic: 'control/log',
    payload: {
        timestamp: new Date().toISOString(),
        device: 'system',
        action: 'emergency_stop',
        parameters: {emergency: true}
    }
});

return [messages];

// Reset emergency stop condition
node.log('Emergency stop reset');

// Clear emergency flags
global.set('emergency_stop', false);
global.set('manual_override', false);

// Log reset action
const logEntry = {
    timestamp: new Date().toISOString(),
    device: 'system',
    action: 'emergency_reset',
    parameters: {emergency: false}
};

// Send info alert
const alert = {
    type: 'info',
    device: 'system',
    message: 'Emergency stop condition reset - System ready for normal operation',
    timestamp: new Date().toISOString()
};

return [{
    topic: 'control/log',
    payload: logEntry
}, {
    topic: 'alert/info',
    payload: alert
}];

// Send system status to dashboard
const data = msg.payload;

// Format data for dashboard widgets
const messages = [];

// System overview
messages.push({
    topic: 'system/overview',
    payload: {
        mode: data.mode,
        pv_power: data.state.pv_power,
        genset_power: data.state.genset_power,
        load_power: data.state.load_power,
        grid_power: data.state.grid_power
    }
});

// Control status
messages.push({
    topic: 'control/status',
    payload: {
        pv_curtailment: data.decisions.pv_curtailment,
        genset_target: data.decisions.genset_target_power,
        export_limit: data.decisions.export_limit_active,
        load_sharing: data.decisions.load_sharing_active
    }
});

return [messages];
